insert into public.test_content (test_id, content, updated_at)
values ('00000000-0000-4000-8000-000000000101', $seed${"id":"listening-mock-1","slug":"listening-mock-1","skill":"listening","title":"CEFR Listening Mock Test 1","targetLevels":["B1","B2","C1"],"durationSec":2400,"audioMode":"per_part","parts":[{"id":"lp1","number":1,"layout":"mcq_response","instructions":"You will hear eight short recordings. For each one, choose the best reply (A, B or C). You will hear each recording twice.","audio":{"assetPath":"listening-mock-1/part1.wav","playLimit":2,"previewSec":20},"transcript":"1. I'm really sorry, but I think I've lost the book you lent me.\n2. Shall we take the bus, or would you rather walk to the station?\n3. Excuse me, do you know if this train stops at Kingsbridge?\n4. You look exhausted. Have you been working late again?\n5. Would you mind turning the music down a little?\n6. I can't decide whether to order the soup or the salad.\n7. Did you manage to fix the printer in the end?\n8. I'm thinking of joining the drama club this term.","items":[{"id":"q1","number":1,"type":"mcq","points":1,"options":[{"key":"A","label":"Don't worry, it happens. I've got another copy."},{"key":"B","label":"Yes, I'd love to borrow it."},{"key":"C","label":"The library closes at six."}],"answer":"A","explanation":{"location":"Part 1, recording 1","quote":"I'm really sorry, but I think I've lost the book you lent me.","reasoning":"A reassuring reply to an apology about a lost book."}},{"id":"q2","number":2,"type":"mcq","points":1,"options":[{"key":"A","label":"It leaves at half past nine."},{"key":"B","label":"Let's walk — it's a lovely evening."},{"key":"C","label":"No, I haven't been there before."}],"answer":"B","explanation":{"location":"Part 1, recording 2","quote":"Shall we take the bus, or would you rather walk to the station?","reasoning":"The question offers a choice; B chooses walking."}},{"id":"q3","number":3,"type":"mcq","points":1,"options":[{"key":"A","label":"I bought a return ticket."},{"key":"B","label":"The platform is over there."},{"key":"C","label":"I'm afraid it doesn't — you'll need the next one."}],"answer":"C","explanation":{"location":"Part 1, recording 3","quote":"Excuse me, do you know if this train stops at Kingsbridge?","reasoning":"A direct answer to a yes/no question about the train stopping."}},{"id":"q4","number":4,"type":"mcq","points":1,"options":[{"key":"A","label":"Yes, we had a deadline to meet."},{"key":"B","label":"No, the office is quite close."},{"key":"C","label":"I'll take a coffee, thanks."}],"answer":"A","explanation":{"location":"Part 1, recording 4","quote":"You look exhausted. Have you been working late again?","reasoning":"A answers the yes/no question and gives a reason."}},{"id":"q5","number":5,"type":"mcq","points":1,"options":[{"key":"A","label":"It's my favourite song too."},{"key":"B","label":"Of course — sorry, I didn't realise it was so loud."},{"key":"C","label":"The speakers are new."}],"answer":"B","explanation":{"location":"Part 1, recording 5","quote":"Would you mind turning the music down a little?","reasoning":"A polite request; B agrees and apologises."}},{"id":"q6","number":6,"type":"mcq","points":1,"options":[{"key":"A","label":"The waiter is coming now."},{"key":"B","label":"I paid by card."},{"key":"C","label":"Why not have both? They're small portions."}],"answer":"C","explanation":{"location":"Part 1, recording 6","quote":"I can't decide whether to order the soup or the salad.","reasoning":"C responds helpfully to the indecision."}},{"id":"q7","number":7,"type":"mcq","points":1,"options":[{"key":"A","label":"No, I've called someone to come and look at it."},{"key":"B","label":"Yes, I'd like ten copies."},{"key":"C","label":"It's on the second floor."}],"answer":"A","explanation":{"location":"Part 1, recording 7","quote":"Did you manage to fix the printer in the end?","reasoning":"A answers whether the printer was fixed."}},{"id":"q8","number":8,"type":"mcq","points":1,"options":[{"key":"A","label":"The tickets sold out quickly."},{"key":"B","label":"That sounds like fun — I might come along too."},{"key":"C","label":"It rained all weekend."}],"answer":"B","explanation":{"location":"Part 1, recording 8","quote":"I'm thinking of joining the drama club this term.","reasoning":"B reacts naturally to the speaker’s plan."}}]},{"id":"lp2","number":2,"layout":"form_completion","instructions":"You will hear a telephone conversation about booking an evening class. Complete the form. Write ONE word or a number in each gap. You will hear the recording twice.","audio":{"assetPath":"listening-mock-1/part2.wav","playLimit":2,"previewSec":20},"transcript":"RECEPTIONIST: Riverside Evening Classes, good morning.\nCALLER: Hello, I’d like to book a place on one of your courses. The pottery class, if there are still spaces.\nRECEPTIONIST: Pottery — yes, there’s room. That one runs on Thursday evenings.\nCALLER: Thursday, great. And what time does it start?\nRECEPTIONIST: It starts at six thirty and runs for two hours.\nCALLER: And how many weeks is the course?\nRECEPTIONIST: It’s eight weeks in total. The cost is twelve pounds per session, paid at the door.\nCALLER: Twelve pounds a session, fine. Do I need to bring anything?\nRECEPTIONIST: We provide the clay and tools, but please bring your own apron — it gets messy!","stem":{"title":"Riverside Evening Classes — Booking Form","html":"<p><strong>Course chosen:</strong> {{q9}}</p><p><strong>Runs on:</strong> {{q10}} evenings</p><p><strong>Start time:</strong> {{q11}}</p><p><strong>Length of course:</strong> {{q12}} weeks</p><p><strong>Cost per session:</strong> £{{q13}}</p><p><strong>Please bring your own:</strong> {{q14}}</p>"},"items":[{"id":"q9","number":9,"type":"gap","points":1,"answer":["pottery"],"explanation":{"location":"Part 2, gap 9","quote":"The pottery class, if there are still spaces.","reasoning":"The answer comes from where the caller asks for the pottery class."}},{"id":"q10","number":10,"type":"gap","points":1,"answer":["Thursday"],"explanation":{"location":"Part 2, gap 10","quote":"That one runs on Thursday evenings.","reasoning":"The answer comes from where the day the class runs."}},{"id":"q11","number":11,"type":"gap","points":1,"answer":["6.30","6:30","half past six","18.30","6.30pm"],"explanation":{"location":"Part 2, gap 11","quote":"It starts at six thirty and runs for two hours.","reasoning":"The answer comes from where the start time."}},{"id":"q12","number":12,"type":"gap","points":1,"answer":["eight","8"],"explanation":{"location":"Part 2, gap 12","quote":"It’s eight weeks in total.","reasoning":"The answer comes from where the length of the course."}},{"id":"q13","number":13,"type":"gap","points":1,"answer":["twelve","12"],"explanation":{"location":"Part 2, gap 13","quote":"The cost is twelve pounds per session.","reasoning":"The answer comes from where the cost per session."}},{"id":"q14","number":14,"type":"gap","points":1,"answer":["apron","an apron"],"explanation":{"location":"Part 2, gap 14","quote":"please bring your own apron","reasoning":"The answer comes from where what students must bring."}}]},{"id":"lp3","number":3,"layout":"matching","instructions":"You will hear four people talking about a course they took. Choose what each speaker liked most (A–H). There are more options than speakers. You will hear the recording twice.","audio":{"assetPath":"listening-mock-1/part3.wav","playLimit":2,"previewSec":20},"optionPool":[{"key":"A","label":"the friendly teacher"},{"key":"B","label":"meeting new people"},{"key":"C","label":"the low cost"},{"key":"D","label":"learning a practical skill"},{"key":"E","label":"the convenient location"},{"key":"F","label":"growing in confidence"},{"key":"G","label":"the flexible timetable"},{"key":"H","label":"the well-equipped rooms"}],"transcript":"Speaker 1: I can actually fix a dripping tap myself now — that’s what I got out of it.\nSpeaker 2: Honestly, I signed up to get out of the house, and I’ve made some really good friends.\nSpeaker 3: I used to hate speaking in front of others; now I don’t mind at all.\nSpeaker 4: What suited me was being able to swap between the morning and evening groups whenever work got busy.","items":[{"id":"q15","number":15,"type":"match","points":1,"prompt":"Speaker 1","answer":"D","explanation":{"location":"Part 3, Speaker 1","quote":"I can actually fix a dripping tap myself now — that’s what I got out of it.","reasoning":"She values having learned a practical, usable skill."}},{"id":"q16","number":16,"type":"match","points":1,"prompt":"Speaker 2","answer":"B","explanation":{"location":"Part 3, Speaker 2","quote":"Honestly, I signed up to get out of the house, and I’ve made some really good friends.","reasoning":"He emphasises the new friendships he made."}},{"id":"q17","number":17,"type":"match","points":1,"prompt":"Speaker 3","answer":"F","explanation":{"location":"Part 3, Speaker 3","quote":"I used to hate speaking in front of others; now I don’t mind at all.","reasoning":"She describes becoming more confident."}},{"id":"q18","number":18,"type":"match","points":1,"prompt":"Speaker 4","answer":"G","explanation":{"location":"Part 3, Speaker 4","quote":"What suited me was being able to swap between the morning and evening groups whenever work got busy.","reasoning":"He praises the flexible timetable."}}]},{"id":"lp4","number":4,"layout":"map_labelling","instructions":"You will hear a guide describing a college floor plan. Label the places on the map. Choose the correct letter (A–H) for each place. You will hear the recording twice.","audio":{"assetPath":"listening-mock-1/part4.wav","playLimit":2,"previewSec":20},"image":{"assetPath":"listening-mock-1/map-plan-1.svg","alt":"Ground floor plan of Greenfield Community College with eight lettered locations A to H, in two rows of four rooms either side of a central corridor, with the entrance at the bottom."},"optionPool":[{"key":"A","label":"A"},{"key":"B","label":"B"},{"key":"C","label":"C"},{"key":"D","label":"D"},{"key":"E","label":"E"},{"key":"F","label":"F"},{"key":"G","label":"G"},{"key":"H","label":"H"}],"transcript":"Welcome to Greenfield Community College. Let me point out where a few things are on this ground-floor plan. Come in through the main entrance and walk up the corridor; turn left at the top and the computer room is right in the far corner on your left. Right next to the computer room, still along the top, you’ll find the main hall. Keep going past the main hall and the library is the third room along the top. Downstairs — I mean on the lower row — the café is in the far left corner, directly below the computer room. The staff room is on the lower row too, the third one along, just below the library.","items":[{"id":"q19","number":19,"type":"match","points":1,"prompt":"The computer room","answer":"A","explanation":{"location":"Part 4, The computer room","quote":"Come in through the main entrance and walk up the corridor; turn left at the top and the computer room is right in the far corner on your left.","reasoning":"Far left corner of the top row = marker A."}},{"id":"q20","number":20,"type":"match","points":1,"prompt":"The main hall","answer":"B","explanation":{"location":"Part 4, The main hall","quote":"Right next to the computer room, still along the top, you’ll find the main hall.","reasoning":"Second room along the top = marker B."}},{"id":"q21","number":21,"type":"match","points":1,"prompt":"The library","answer":"C","explanation":{"location":"Part 4, The library","quote":"Keep going past the main hall and the library is the third room along the top.","reasoning":"Third room along the top = marker C."}},{"id":"q22","number":22,"type":"match","points":1,"prompt":"The café","answer":"E","explanation":{"location":"Part 4, The café","quote":"Downstairs — I mean on the lower row — the café is in the far left corner, directly below the computer room.","reasoning":"Far left of the bottom row = marker E."}},{"id":"q23","number":23,"type":"match","points":1,"prompt":"The staff room","answer":"G","explanation":{"location":"Part 4, The staff room","quote":"The staff room is on the lower row too, the third one along, just below the library.","reasoning":"Third room along the bottom = marker G."}}]},{"id":"lp5","number":5,"layout":"multi_extract_mcq","instructions":"You will hear three short extracts. For each extract, answer the two questions by choosing A, B or C. You will hear each extract twice.","audio":{"assetPath":"listening-mock-1/part5.wav","playLimit":2,"previewSec":20},"transcript":"[You will hear two students, Mark and Lucy, discussing their history project.]\nMARK: So, are we agreed on the topic? I still think the Industrial Revolution is too broad.\nLUCY: I know, but I really don’t want to do the Roman one — we can’t seem to agree, can we?\nMARK: No. Look, rather than going round in circles, why don’t we just ask Dr Evans what she thinks in tomorrow’s tutorial?\nLUCY: Good idea. Let’s get her advice first, then decide.\n\n[You will hear a tutor giving a student feedback on a presentation.]\nTUTOR: Overall, well done. The best thing was how clearly it was organised — I could follow your argument from start to finish without getting lost. One thing, though: you rushed. If you slow down a little next time, the audience will take in far more of your excellent points.\n\n[You will hear a woman talking about a cycling holiday.]\nWOMAN: People asked why I didn’t just drive. But that’s the point — on a bike you go slowly enough to really take in the countryside, the villages, everything. It wasn’t always easy, mind you. The rain held off, and I always found a bed for the night, but those hills — some days I thought my legs would give up completely!","groups":[{"id":"g1","context":"You will hear two students, Mark and Lucy, discussing their history project.","items":[{"id":"q24","number":24,"type":"mcq","points":1,"prompt":"What problem do Mark and Lucy have?","options":[{"key":"A","label":"They cannot find enough sources."},{"key":"B","label":"They disagree about the topic."},{"key":"C","label":"They are running out of time."}],"answer":"B","explanation":{"location":"Part 5, question 24","quote":"we can’t seem to agree, can we?","reasoning":"They can’t agree on which topic to choose."}},{"id":"q25","number":25,"type":"mcq","points":1,"prompt":"What do they decide to do next?","options":[{"key":"A","label":"Ask their tutor for advice."},{"key":"B","label":"Divide the work between them."},{"key":"C","label":"Change to an easier subject."}],"answer":"A","explanation":{"location":"Part 5, question 25","quote":"why don’t we just ask Dr Evans what she thinks","reasoning":"They decide to get their tutor’s advice first."}}]},{"id":"g2","context":"You will hear a tutor giving a student feedback on a presentation.","items":[{"id":"q26","number":26,"type":"mcq","points":1,"prompt":"What does the tutor praise?","options":[{"key":"A","label":"The clear structure."},{"key":"B","label":"The choice of images."},{"key":"C","label":"The length."}],"answer":"A","explanation":{"location":"Part 5, question 26","quote":"The best thing was how clearly it was organised","reasoning":"The tutor praises the clear organisation/structure."}},{"id":"q27","number":27,"type":"mcq","points":1,"prompt":"What does the tutor suggest improving?","options":[{"key":"A","label":"Speaking more slowly."},{"key":"B","label":"Including more data."},{"key":"C","label":"Making more eye contact."}],"answer":"A","explanation":{"location":"Part 5, question 27","quote":"you rushed. If you slow down a little next time","reasoning":"The tutor advises slowing down."}}]},{"id":"g3","context":"You will hear a woman talking about a cycling holiday.","items":[{"id":"q28","number":28,"type":"mcq","points":1,"prompt":"Why did the woman choose cycling?","options":[{"key":"A","label":"It was cheaper than other options."},{"key":"B","label":"She wanted to see the countryside slowly."},{"key":"C","label":"A friend recommended it."}],"answer":"B","explanation":{"location":"Part 5, question 28","quote":"on a bike you go slowly enough to really take in the countryside","reasoning":"She chose cycling to experience the countryside slowly."}},{"id":"q29","number":29,"type":"mcq","points":1,"prompt":"What was the biggest challenge?","options":[{"key":"A","label":"The weather."},{"key":"B","label":"The hills."},{"key":"C","label":"Finding places to stay."}],"answer":"B","explanation":{"location":"Part 5, question 29","quote":"those hills — some days I thought my legs would give up","reasoning":"The rain held off and she found beds, but the hills were hard."}}]}]},{"id":"lp6","number":6,"layout":"note_completion","instructions":"You will hear part of a talk about the history of chocolate. Complete the notes. Write ONE word in each gap. You will hear the talk twice.","audio":{"assetPath":"listening-mock-1/part6.wav","playLimit":2,"previewSec":20},"transcript":"Today I want to tell you a little about where chocolate comes from. It all begins with the cacao tree, which first grew wild in the rainforests of Central and South America. The ancient Maya prized the beans so highly that they actually used them as money — you really could buy things with a handful of cacao beans. For a very long time, though, nobody ate chocolate; it was only ever taken as a bitter drink. It was Spanish explorers who brought it back to Europe in the sixteenth century. Europeans didn’t much like the bitterness, so they added sugar to make the drink sweet, and it quickly became fashionable. And the chocolate we know best? The very first solid chocolate bar wasn’t produced until the 1840s.","stem":{"title":"Talk: A Short History of Chocolate","html":"<p>The cacao tree first grew in the rainforests of Central and South {{q30}}.</p><p>The ancient Maya valued the beans so highly that they used them as {{q31}}.</p><p>For centuries, chocolate was only ever taken as a bitter {{q32}}.</p><p>Spanish explorers brought it to {{q33}} in the sixteenth century.</p><p>Europeans added sugar to make the drink {{q34}}.</p><p>The first solid chocolate {{q35}} was produced in the 1840s.</p>"},"items":[{"id":"q30","number":30,"type":"gap","points":1,"answer":["America"],"explanation":{"location":"Part 6, gap 30","quote":"first grew wild in the rainforests of Central and South America","reasoning":"The answer comes from where the talk mentions where the cacao tree first grew."}},{"id":"q31","number":31,"type":"gap","points":1,"answer":["money","currency"],"explanation":{"location":"Part 6, gap 31","quote":"they actually used them as money","reasoning":"The answer comes from where the talk mentions what the Maya used the beans as."}},{"id":"q32","number":32,"type":"gap","points":1,"answer":["drink","beverage"],"explanation":{"location":"Part 6, gap 32","quote":"it was only ever taken as a bitter drink","reasoning":"The answer comes from where the talk mentions how chocolate was taken."}},{"id":"q33","number":33,"type":"gap","points":1,"answer":["Europe"],"explanation":{"location":"Part 6, gap 33","quote":"brought it back to Europe in the sixteenth century","reasoning":"The answer comes from where the talk mentions where explorers brought it."}},{"id":"q34","number":34,"type":"gap","points":1,"answer":["sweet","sweeter"],"explanation":{"location":"Part 6, gap 34","quote":"they added sugar to make the drink sweet","reasoning":"The answer comes from where the talk mentions what sugar made the drink."}},{"id":"q35","number":35,"type":"gap","points":1,"answer":["bar","bars"],"explanation":{"location":"Part 6, gap 35","quote":"The very first solid chocolate bar wasn’t produced until the 1840s","reasoning":"The answer comes from where the talk mentions the first solid chocolate item."}}]}]}$seed$::jsonb, now())
on conflict (test_id) do update set content=excluded.content, updated_at=now();
